long long solve(vector<long long> value, vector<long long> limit) {
    int n = value.size();
    // Use a max-heap to always activate the element with the highest value
    // We'll store (-value[i], limit[i], i) to simulate a max-heap
    vector<vector<long long>> heap;
    for (int i = 0; i < n; ++i) {
        heap.push_back({-value[i], limit[i], i});
    }
    // Heapify the vector to turn it into a heap
    make_heap(heap.begin(), heap.end(), [](vector<long long> a, vector<long long> b) {
        return a[0] < b[0]; // Max-heap based on -value[i]
    });

    // Track the current number of active elements
    int active_count = 0;
    // Track which elements are active
    vector<bool> active(n, false);
    // Track which elements are inactive
    vector<bool> inactive(n, true);

    long long total = 0;

    while (!heap.empty()) {
        vector<long long> top = heap[0];
        long long val = -top[0];
        long long lim = top[1];
        int i = top[2];

        // Check if the element can be activated
        if (active_count < lim && !active[i]) {
            // Activate the element
            active[i] = true;
            inactive[i] = false;
            total += val;
            active_count += 1;

            // Now, check which elements become inactive
            // All elements j where limit[j] <= active_count
            for (int j = 0; j < n; ++j) {
                if (inactive[j] && limit[j] <= active_count) {
                    inactive[j] = true;
                    active[j] = false;
                }
            }
        }

        // Pop the top element from the heap
        pop_heap(heap.begin(), heap.end(), [](vector<long long> a, vector<long long> b) {
            return a[0] < b[0]; // Max-heap based on -value[i]
        });
        heap.pop_back();
    }

    return total;
}
